import { useState } from "react";
const Addon = () => {
    const [TaskName, SetTaskName] = useState("")
    const [TaskDetails, SetTaskDetails] = useState("")
    const [Taskstatus, SetTaskstatus] = useState("Yet to start")
    const handlesubmit =(e) =>{
        const TaskUploads = {TaskName,TaskDetails,Taskstatus}
        fetch("http://localhost:8000/TaskUploads",{
            method : "POST",
            headers :{"Content-Type": "application/json"}

        }
        )
    }
    return (
        <div className="create">
            <h3>New Task</h3>
            <form>
                <label>Task Name</label>
                <input type="text" required value={TaskName} placeholder="Task Name" />
                <label>Detail of the task</label>
                <textarea required value={TaskDetails} onchange placeholder="Detail of the Task" />
                <label>Status</label>
                <select required value={Taskstatus} >
                    <option value="Yet to start">Yet to start</option>
                    <option value="In Progress">In Progress</option>
                    <option value="Completed">Completed</option>
                </select>
            </form>
            <button input="submit">Save</button>
        </div>
    )
}

export default Addon
